var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"이름 맥스웰. 키는 172에 검붉은 머리와 호리호리한 체형이 특징이라….","JPN":"名前、マックスウェル。身長は172に赤黒い髪とスレンダーな体型が特徴、か……","ENG":"A slim man, 172 cm tall with dark red hair named Maxwell...","TWN":"姓名，麥斯威爾，身高172，特色是紅色頭髮和身材纖細…"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"제길. 그것 참 단단히도 꼬였군.","JPN":"くそ。面倒なことになったな。","ENG":"Dammit. This isn't gonna be easy.","TWN":"該死，人這麼多是要怎麼找。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"멍청이가 아니고서야 그대로 다닐 리는 없을 테고, 목소리 정도로 알아챌 수밖에 없나?","JPN":"そのまま歩き回るバカでもないだろうし、声で察するしかないか？","ENG":"He won't be walking around with that appearance unless he's a fool. So, I need to find him just by his voice?","TWN":"他又不是笨蛋，肯定不會用平常的樣子出現吧？難道只能靠認聲音嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"다른 녀석들은…….","JPN":"他のやつらは……","ENG":"The others were–","TWN":"其他人呢……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"쫄리면 뒤지십시오, 휴먼.","JPN":"ビビったのなら飛び降りなさい、ヒューマン。","ENG":"Fold if you are feeling the heat, human.","TWN":"怕的話就蓋牌吧，人類。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"크윽! 주, 죽겠습니다….","JPN":"くうっ！　お、降ります……","ENG":"Kgh! I-I fold...","TWN":"可惡！輸了…"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"저 여자. 굉장하잖아! 벌써 몇 연승째야?","JPN":"あの女、すごいな！　もう何連勝だ？","ENG":"She's incredible! What a win streak!","TWN":"那女的，好強！她都連續贏幾次啦？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"칩이란 칩은 다 쓸어 담고 있어. 저런 실력자가 대체 어디서…!","JPN":"全部のチップをかき集めてる。いったいどこであんな凄腕が……！","ENG":"She's scraping up all the chips. Where did someone like her even come from...?","TWN":"她的籌碼多到檯面上都放不下咧，她到底是誰…！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"……저 빌어먹을 고철.","JPN":"……あのくそ鉄くず。","ENG":"...That scrap metal.","TWN":"……那個該死的廢鐵。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"꼬맹이 쪽은….","JPN":"ガキの方は……","ENG":"How's the kid doing...?","TWN":"小鬼呢…"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"그래서…! 있는 돈이란 돈은 다 날려버렸어!","JPN":"それで……！　ありったけのお金を無くしちゃったんだ！","ENG":"That's how...! I blew away all my money!","TWN":"所以…！我的錢全輸光了！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"이런 사람을 대체, 대체 누가 좋아해 주겠냐고!","JPN":"いったい誰が、誰がこんな人間を愛してくれるんだよ！","ENG":"How can anyone like someone like me?!","TWN":"到底誰會喜歡我這種人！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"괜찮아요! 누가 그랬는데, 불행이란 건 상대적인 거래요.","JPN":"大丈夫です！　どこかで聞いたんですけど、不幸ってものは相対的なものですって。","ENG":"It's all right! Someone told me that unhappiness is relative.","TWN":"沒事的！有人說過，不幸是比較出來的。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"아저씨는 이곳에 왜 오셨나요?","JPN":"おじさんはどうしてここに？","ENG":"But why did you come here, mister?","TWN":"叔叔你怎麼會來這裡？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"그, 그야… 게임에서 딴 돈으로 빚을 탕감하기 위해서지.","JPN":"そ、そりゃ……ゲームで稼いだお金で、借金を返すためだな。","ENG":"Th-that's... so I can win big and pay off my debts.","TWN":"因為…我想要用贏來的錢還債。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"이런 확률 낮은 도박에 기대야 할 정도로 내 삶은 불행하다고!","JPN":"こんな確率の低い賭けに頼らないとダメなほど、俺の人生は不幸なんだ！","ENG":"My life is so unfortunate that I have to play these low-probability gambling games!","TWN":"人家說十賭九輸，我竟然還來賭，難怪我的人生會這麼悲慘！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"하지만 확률 낮은 게임에 도전할 정도로 아저씨는 용기 있는 분이시잖아요.","JPN":"でも、確率の低いゲームに挑戦するくらいだから、おじさんは勇気のある方でしょう？","ENG":"But it shows that you're brave enough to challenge these low-probability games.","TWN":"贏的機率這麼低你還敢來賭，就表示你很有勇氣呢。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"이깟 슬롯머신에서 잭팟을 터트리는 것보다, 까짓거 인생. 별거 아닐 거예요!","JPN":"スロットマシンでジャックポットを当てることより、人生なんて大したことないはずです！","ENG":"Life will be easier than hitting a jackpot on one of the slot machines!","TWN":"人生再怎麼難，也不會比在拉霸機中頭獎還要難，沒事的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"눈물 요정아, 달아나라! 뚝!","JPN":"涙の妖精よ、飛んでけ！","ENG":"Go away, tear fairy! Shoo!","TWN":"眼淚仙子，快快走。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"그래! 슬롯머신은 7을 세 개나 띄워야 하지만, 인생은 한 번 성공하면 그만이야!","JPN":"そうだ！　スロットマシンは7を三つも出さなきゃだけど、人生は一度成功すると良し！","ENG":"Yeah! I have to get three 7s in a slot machine to win, but just one lucky break in life!","TWN":"沒錯！拉霸機要出現三個7才可以，但人生只需要一次的成功！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L41_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"난… 난 할 수 있어!","JPN":"俺は……俺はできる！","ENG":"I... I can do it!","TWN":"我…我可以的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"가지가지하는군. 사채업에 손을 대고 쫓기듯 온 곳이 카지노인 주제에.","JPN":"ふざけやがって。闇金に手を出して、追われて来たところがカジノだろうが。","ENG":"Nonsense. You borrowed money from a loan shark and ran away to a casino.","TWN":"胡說八道什麼，竟然跟高利貸借錢來賭場。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"언니! 오셨어요?","JPN":"お姉ちゃん！　来ましたね。","ENG":"Rita! You're here!","TWN":"姊姊！你來啦？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"그래. 의도한 건 아니었겠지만 잘했다. 꼬맹아.","JPN":"ああ。意図してなかっただろうが、よくやった。ガキ。","ENG":"Yeah. I know it wasn't intended, but good job, kid.","TWN":"嗯嗯，幹得好，小鬼，雖然我知道你只是無心插柳柳成陰。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"응? 언니…?","JPN":"え？　お姉ちゃん……？","ENG":"Hmm? Rita...?","TWN":"嗯？姊姊…？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"다, 당신은 호라이즌 파이낸…!","JPN":"あ、あなたは、ホライズンファイナン……！","ENG":"Y-you're from Horizon Finance...!","TWN":"你…你不是地平線金融的…！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"입 다물어. 팔 한 짝 없는 반송장으로 남들 가십거리가 되기 싫다면 말이야.","JPN":"黙れ。腕一本がない半死体のまま、ゴシップになりたくなければな。","ENG":"Shut it, unless you want to be a corpse with one arm and become the talk of the town.","TWN":"閉上你的嘴，否則我會把你打得連你爸媽都認不出來。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"맥스웰. 조항은 기억하고 있겠지?","JPN":"マックスウェル。条件、忘れてないだろうな？","ENG":"Maxwell. You remember our terms, correct?","TWN":"麥斯威爾，你還記得你有跟我們借錢吧？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"만기일이 지났으니 손님으로 우대받을 생각은 버리는 게 좋을 거야.","JPN":"返済日が過ぎている、お客さん扱いされるとは思わない方がいい。","ENG":"Since you're past your deadline, don't expect us to treat you as a customer now.","TWN":"期限已經到了，別想我們還會對你客客氣氣的。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"돈이 준비되지 않았다면, 지금이라도 유서 쓸 시간을 주지.","JPN":"お金が準備できていないのなら、今にも遺書を書く時間を与えてやる。","ENG":"If you don't have the money ready, I'll give you some time to write a will.","TWN":"錢還沒準備好的話，你現在就可以寫遺書了。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"자, 잠시만…! 잠시만 기다려 주십시오!","JPN":"ちょ、ちょっと……！　ちょっと待ってください！","ENG":"W-wait...! Just give me a bit more time!","TWN":"先…先等一下…！等等！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"닥쳐. 이미 충분히 기다렸으니까.","JPN":"黙れ。もう十分待った。","ENG":"Shut it. We've waited long enough.","TWN":"閉嘴，我們已經等夠久了。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"그, 그렇지만…! 정말로 돈이 없단 말입니다.","JPN":"で、でも……！　本当にお金がないんです。","ENG":"B-but...! I really don't have the money.","TWN":"可…可是…！我真的沒錢。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"방금 마지막 남은 재산마저 탕진한 뒤라고요…! 정말입니다!","JPN":"さっき最後の金まで使い切って……！　本当ですよ！","ENG":"I just went broke using up whatever I had left and lost...! I'm telling you the truth!","TWN":"剛才連我僅存的一點錢也都輸光了…！是真的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"쯧.","JPN":"チッ。","ENG":"Tsk.","TWN":"嘖。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"쿨럭! 쿨럭!","JPN":"ゲホッ！　ゲホッ！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"아저씨. 괜찮으세요?","JPN":"おじさん。大丈夫ですか？","ENG":"Are you okay, mister?","TWN":"叔叔，你還好嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"살갑게 굴지 말고 어디 안 가도록 감시나 해, 꼬맹이.","JPN":"馴れ馴れしくしないでどこにも行かないように監視でもしてろ、ガキ。","ENG":"Hey kid. Stop asking if he's okay and keep an eye on him so he doesn't run away.","TWN":"你那麼關心他幹嘛？把人給我看好，小鬼。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"운 좋은 줄 알아, 맥스웰.","JPN":"運がいいな、マックスウェル。","ENG":"You're a lucky fellow, Maxwell.","TWN":"算你走運，麥斯威爾。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"호라이즌이랑 같이 오지 않았다면, 네 팔 한 짝은 이미 걸레짝처럼 변했을 테니까.","JPN":"ホライズンと一緒じゃなかったら、お前の片腕はもうボロボロになってただろうから。","ENG":"If Horizon didn't come with me, one of your arms would be ripped off by now.","TWN":"地平線沒有和我一起來，否則你的手早就不在了。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"사기꾼 포착. 손목을 분쇄합니다.","JPN":"ペテン師を捕まえました。手首を粉砕します。","ENG":"Cheater spotted. Crushing wrist.","TWN":"捕獲騙徒，粉碎手腕。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"끄아아아악!","JPN":"クアアアアッ！","ENG":"Gaaaah!","TWN":"呃啊啊啊！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L36_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"갬블을 하라 했지 사기치라 한 적 없습니다, 휴먼. 실력을 키워 다시 도전하십시오.","JPN":"ペテンではなくギャンブルしろと言ったはずです、ヒューマン。実力を磨き、また挑戦するように。","ENG":"I told you to gamble, not cheat, human. Come back once your skills have improved.","TWN":"我叫你下注，沒叫你詐賭，人類。回家練練再來挑戰吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"나도 여기서 노름판이나 벌리라고 한 기억은 없는데 말이지.","JPN":"私もここで開帳しろとは言ってなかったはずだがな。","ENG":"I don't remember telling you to open a gambling ring here.","TWN":"我也記得我沒叫你在這裡賭錢吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"오셨습니까, 리타.","JPN":"お帰りなさい、リタ。","ENG":"You are here, Rita.","TWN":"你來了，麗塔。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"…치워, 꼬맹이가 보기 전에.","JPN":"……片付けろ、ガキが見る前に。","ENG":"...Move him before the kid sees.","TWN":"…快收拾好，別讓小鬼看到。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"걱정마십시오. 심신 케어 역시 호라이즌 파이낸스가 자랑하는 복지 중 하나입니다.","JPN":"ご心配なく。心身ともどものケアもまた、ホライズン・ファイナンスが誇る福利厚生の一つです。","ENG":"Not to worry. Mental care is one of the welfare benefits of Horizon Finance.","TWN":"你放心，我們地平線金融的福利之一，就是非常關心員工的身心狀況。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"맥스웰은 찾았습니까?","JPN":"マックスウェルは見つかりましたか？","ENG":"Did you find Maxwell?","TWN":"找到麥斯威爾了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"찾았지만 빈털터리야. 갬블에 미쳐 이미 전재산을 탕진한 것 같더군.","JPN":"見つかったが、一文無しだ。ギャンブルにハマってすでに全財産を注ぎ込んだようだ。","ENG":"I did, but he's broke. He went all out on gambling and lost it all.","TWN":"人是找到了，但他一毛錢也沒有，似乎賭博賭到傾家蕩產。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"그러니까 골라. 오른쪽으로 할지, 왼쪽으로 할지.","JPN":"だから、選べ。右にするか、左にするか。","ENG":"So choose. Will it be his right or left side?","TWN":"所以你選吧，要左邊還右邊？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"제게 홀짝으로 승부를 걸다니. 배짱도 좋군요, 리타.","JPN":"私に丁半で挑むとは。いい度胸ですね、リタ。","ENG":"I see you have the guts to challenge me to a game of odds and evens, Rita.","TWN":"你竟然敢跟我賭，算你有種，麗塔。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"개소리하지 말고 정해. 채무불량자인 이상, 정상적으로 돈을 받는 건 포기해야 할 테니까.","JPN":"ふざけないで決めろ。悪質債務者である以上、普通にお金をもらうことは諦めないといけないからな。","ENG":"Cut the crap and choose. Since he's unable to pay us back, we have to get creative with our ways of getting our money.","TWN":"少胡說八道，快點決定。既然他已經有不良紀錄，我看他是不會正常還款的。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"그게 싫다면 프론트 베이에라도 보내야겠지.","JPN":"それが嫌なら、フロントベイにでも送るべきだろう。","ENG":"If you don't like that either, then we'll have to send him to Front Bay.","TWN":"還是要賣去前灣？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"……흠.","JPN":"……ふむ。","ENG":"...Hmm.","TWN":"嗯……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"맥스웰은 아티팩트를 담보로 판돈을 준비한 것 같더군요.","JPN":"マックスウェルはアーティファクトを担保に掛け金を用意したようです。","ENG":"Maxwell put down an Artifact as collateral for borrowing money for gambling.","TWN":"麥斯威爾好像有拿人造神器當作賭注的擔保。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"그래. 그런 얘기를……","JPN":"そう。そんな話を……","ENG":"Yeah. That's the...","TWN":"對，提這個要……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"잠깐. 그건 어떻게 안 거야?","JPN":"ちょっと待て。それはどうやって知ったんだ？","ENG":"Wait. How did you know that?","TWN":"等等，你怎麼知道？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"직원이 일하는데 제가 정말 놀음판이나 벌였겠습니까.","JPN":"スタッフが働いているのに、私が本当にギャンブルなんかしてたと思うのですか？","ENG":"Do you really think I would be gambling while my employees are out working for me?","TWN":"你以為我是那種員工在工作，自己卻跑去賭錢的老闆嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"딜러복의 넥타이 부근을 잘 보십시오, 리타.","JPN":"ディーラー服のネクタイ辺りをよく見てください、リタ。","ENG":"Rita, look closely at the tie on the dealer's uniform.","TWN":"你看荷官領帶的地方。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"이건… 소형 카메라?","JPN":"これは……小型のカメラ？","ENG":"Is that... a miniature camera?","TWN":"那是…小型攝影機？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"과연. 본인들이 사기를 치더라도 남의 사기는 용납 못 한다 이건가?","JPN":"なるほど。本人たちはペテンにかけても、他人のペテンは許せないというのか。","ENG":"I see. They can cheat, but they won't tolerate others cheating, eh?","TWN":"這就是所謂的，作賊喊抓賊嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"이런 거추장스러운 옷을 왜 고집하나 했는데…….","JPN":"なんでこんな面倒な服にこだわるのかと思えば……","ENG":"I always wondered why they kept insisting on wearing this outfit...","TWN":"我還想說為什麼要堅持穿這種羞恥的衣服……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"모든 카메라를 확인한 결과, 맥스웰로 추정되는 인물의 게임 영상을 확보했습니다.","JPN":"すべてのカメラを確認した結果、マックスウェルと推定される人物のゲーム映像を確保しました。","ENG":"After checking all the cameras, I have secured the game footage of the person assumed to be Maxwell.","TWN":"我確認過攝影機的內容，在影片中發現疑似麥斯威爾的人。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"당연하지만 사기 행각이 일어나더군요.","JPN":"当然ながら、詐欺が行われていました。","ENG":"And of course, he was cheated.","TWN":"雖然不易外，但確實有詐賭行為。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"아티팩트의 소유권이 저희에게 있다는 것만 증명하면 충분할 정도로.","JPN":"アーティファクトの所有権が私たちにあることさえ証明できれば十分なくらいに。","ENG":"This should be enough to prove that the Artifact is now ours.","TWN":"我們只需要證明人造神器的所有權屬於我們。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"칩을 쓸어 담아 사장의 눈에는 띈 상황입니다. 호출도 왔으니, 일을 끝내러 가죠.","JPN":"チップをかき集めて社長の目についた状況です。呼び出しも来ていますので、仕事を終わらせに行きましょう。","ENG":"The casino CEO is keeping an eye on me after I swept all of the chips. I've even received a call from him, so let us finish this quick.","TWN":"賭場老闆已經發現到我們的存在，現在要把我們找過去，去把事情解決掉吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"그래. 드디어 이 지긋지긋한 바니걸이랑도 결별이군.","JPN":"ああ。やっとこのうんざりしたバーニーガール服装ともお別れだな。","ENG":"Yeah. I finally get to take this stupid bunny girl suit off.","TWN":"好，終於可以和這個討厭的兔女郎說再見。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"언니! 대표님! 허억…! 언니가 준 종이에, 아저씨 싸인을 받아왔어요!","JPN":"お姉ちゃん！　代表！　はあ……！　お姉ちゃんがくれた紙に、おじさんにサインしてもらいました！","ENG":"Rita! Boss! *Huff...!* I got the mister's signature on the paper Rita gave me!","TWN":"姊姊！BOSS！呼呼…！叔叔在姊姊給我的紙上簽名了！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"되게 오래 고민하셨는데, 결국 종이를 달라 하시더라고요.","JPN":"結構悩んでましたけど、結局を紙ちょうだいって。","ENG":"He seemed hesitant at first, but he eventually asked me to give him the paper.","TWN":"叔叔考慮了好久，最後才終於在紙上簽名。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"처음에는 그렇게 싫어하셨는데, 무슨 마법의 주문이라도 건 건가요?","JPN":"最初はあんなに嫌がっていたのに、いったいどんな魔法の呪文を使ったんですか？","ENG":"He didn't look like he wanted to at first. Did you cast some kind of magic spell on him?","TWN":"他一開始明明很不願意的，姊姊是有對他施什麼魔法嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"주문보다는 조언에 가깝지. 만기일이 더 지나면 어떤 일이 일어날지 귀띔해줬을 뿐이니까.","JPN":"呪文というよりは助言だな。これ以上日にちが過ぎると、どんなことが起きるのか耳打ちをしてやっただけだ。","ENG":"More advice than magic. I told him what would happen if he was overdue with his payments.","TWN":"與其說是魔法，應該說是建議吧。我只是暗示他再不還錢接下來會發生什麼事而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"그럼, 챙겨야 할 건 전부 챙긴 건가?","JPN":"では、必要なものは全部揃ったのか？","ENG":"Then, do we have everything we need?","TWN":"好了，東西都帶了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"네. 판돈도 충분하니, 썩 나쁘지 않은 게임이 되겠군요.","JPN":"はい。掛け金も十分ですので、結構悪くないゲームになりそうです。","ENG":"Yes. Since we have enough money to bet, this will be an interesting game.","TWN":"是，有這麼多賭金，應該可以好好賭一場。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"좋아.","JPN":"よし。","ENG":"Good.","TWN":"很好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"지금부터는 원래 방식대로 가자고.","JPN":"これからは元どおりに行こう。","ENG":"Now, we go back to how we've always done business.","TWN":"現在開始要用我們自己的方式。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};